INSERT INTO `v1_ba028275fe08c2edbfe9030d95b42a263281a77c5eddfa7195554cf42db57c5f` VALUES ("ツムギのボトルキャップ", 1, 11601, "ツムギ・オンステージ！ツムギがキャップのステージでかわいく\nポーズを決めている。どこでも好きな場所に気軽に飾ることが可\n能。", 0.625, 6, 0.75);
